/**
 * CompleteNewPasswordPage Component
 *
 * 一時パスワードでログインしたユーザーが新しいパスワードを設定するページ。
 * ログインページからstate経由でemail・sessionを受け取る。
 *
 * ルート: /complete-new-password
 */

import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { Button, ErrorMessage, InputField } from '../components';

const CompleteNewPasswordPage: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { login, completeNewPassword } = useAuth();

  // ログインページからstate経由で受け取る
  const { email, session } = (location.state as { email: string; session: string }) || {};

  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // stateが取得できない場合はログインへ
  if (!email || !session) {
    navigate('/login', { replace: true });
    return null;
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (newPassword !== confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    if (newPassword.length < 8) {
      setError('Password must be at least 8 characters.');
      return;
    }

    setIsSubmitting(true);
    try {
      // 新パスワードを設定
      await completeNewPassword(email, newPassword, session);
      // AuthContextを通じて再ログインしてダッシュボードへ
      // (AuthGuardが認証状態を正しく認識するため)
      await login(email, newPassword);
      navigate('/dashboard', { replace: true });
    } catch (err: unknown) {
      const errorMessage =
        err instanceof Error ? err.message : 'Failed to set password. Please try again.';
      setError(errorMessage);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
      <div className="sm:mx-auto sm:w-full sm:max-w-md">
        <h1 className="text-center text-3xl font-bold text-gray-900">User Auth System</h1>
        <h2 className="mt-6 text-center text-2xl font-semibold text-gray-700">Set New Password</h2>
        <p className="mt-2 text-center text-sm text-gray-600">
          You logged in with a temporary password. Please set a new password to continue.
        </p>
      </div>

      <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
        <div className="bg-white py-8 px-4 shadow-lg sm:rounded-lg sm:px-10">
          <form onSubmit={handleSubmit} className="space-y-6">
            {error && <ErrorMessage message={error} variant="error" />}

            {/* Email (読み取り専用) */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Email Address</label>
              <p className="text-sm text-gray-900 bg-gray-50 px-3 py-2 rounded-md border border-gray-200">
                {email}
              </p>
            </div>

            {/* New Password */}
            <InputField
              id="newPassword"
              name="newPassword"
              type="password"
              label="New Password"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              placeholder="Enter new password"
              required
              autoComplete="new-password"
            />

            {/* Confirm Password */}
            <InputField
              id="confirmPassword"
              name="confirmPassword"
              type="password"
              label="Confirm New Password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              placeholder="Confirm new password"
              required
              autoComplete="new-password"
            />

            <Button
              type="submit"
              variant="primary"
              className="w-full"
              loading={isSubmitting}
              disabled={isSubmitting}
            >
              {isSubmitting ? 'Setting password...' : 'Set New Password'}
            </Button>
          </form>
        </div>
      </div>

      <div className="mt-8 text-center">
        <p className="text-xs text-gray-500">&copy; 2025 User Auth System. All rights reserved.</p>
      </div>
    </div>
  );
};

export default CompleteNewPasswordPage;
